mapper.select:
select cop.id, cop.payment_no, cop.shopping_order_no, cop.buyer_id, cop.merchant_id, cop.user_charge_account, cop.merchant_charge_account, cop.create_time,
       cop.amount, cop.trade_state as paymentState, cop.payment_type, cop.trade_flow_no, cc.username as username, cmi.merchant_name
from cm_order_payment cop
left join cm_order_shopping cos on cop.shopping_order_no = cos.order_no
left join cm_customer cc on cop.buyer_id = cc.user_id
left join cm_merchant_info cmi on cos.merchant_id = cmi.id
where cop.deleted = '0'

	and cos.merchant_id = #{vo.merchantId}


	and cop.payment_no = #{vo.paymentNo}


	and cop.payment_type = #{vo.paymentType}


	and cop.trade_state = #{vo.tradeState}


	and cop.create_time >= #{vo.createTimeStart}


	and cop.create_time < #{vo.createTimeEnd}


	and cop.amount >= cast(#{vo.amountMin} as DECIMAL)


	and cop.amount < cast(#{vo.amountMax} as DECIMAL)

order by cop.create_time desc

select sum(amount) as income, count(*) as orderCount
from cm_order_payment
where trade_state = 3 and merchant_id = #{merchantId} and create_time > #{start}
